func solve(weight []int64) int64 {
    n := int64(len(weight))
    if n < 2 {
        return 0
    }

    var res int64 = 0
    i := int64(0)
    for i < n {
        maxVal := weight[i]
        lastVal := weight[i]
        j := i + 1
        found := false
        for j < n {
            if weight[j] > maxVal {
                maxVal = weight[j]
            }
            lastVal = weight[j]
            if lastVal < maxVal {
                res++
                i = j + 1
                found = true
                break
            }
            j++
        }
        if !found {
            i++
        }
    }
    return res
}
